// Some portions generated by Codex
package org.eclipse.rdf4j.common.xml;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatExceptionOfType;

import java.io.ByteArrayInputStream;
import java.io.InputStream;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;
import org.w3c.dom.Document;
import org.xml.sax.InputSource;
import org.xml.sax.SAXException;

class XMLReaderFactoryTest {

	@TempDir
	Path tempDir;

	@AfterEach
	void clearSystemProperties() {
		System.clearProperty(XMLReaderFactory.DISALLOW_DOCTYPE_DECL_PROPERTY);
	}

	@Test
	void xmlReaderRejectsDoctypeUnlessSystemPropertyAllowsIt() throws Exception {
		assertThatExceptionOfType(SAXException.class)
				.isThrownBy(() -> XMLReaderFactory.createXMLReader().parse(inputSource("<!DOCTYPE root><root/>")))
				.withMessageContaining("DOCTYPE is disallowed");

		System.setProperty(XMLReaderFactory.DISALLOW_DOCTYPE_DECL_PROPERTY, "false");

		XMLReaderFactory.createXMLReader().parse(inputSource("<!DOCTYPE root><root/>"));
	}

	@Test
	void documentUtilRejectsDoctype() throws Exception {
		URL document = writeDocument("<!DOCTYPE root><root/>");

		assertThatExceptionOfType(Exception.class)
				.isThrownBy(() -> DocumentUtil.getDocument(document))
				.withMessageContaining("DOCTYPE is disallowed");
	}

	@Test
	void documentUtilParsesSafeXml() throws Exception {
		URL document = writeDocument("<root><child>value</child></root>");

		Document parsed = DocumentUtil.getDocument(document);

		assertThat(parsed.getDocumentElement().getNodeName()).isEqualTo("root");
		assertThat(parsed.getElementsByTagName("child").item(0).getTextContent()).isEqualTo("value");
	}

	private URL writeDocument(String xml) throws Exception {
		Path document = tempDir.resolve("document.xml");
		Files.writeString(document, xml, StandardCharsets.UTF_8);
		return document.toUri().toURL();
	}

	private InputSource inputSource(String xml) {
		InputStream stream = new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8));
		return new InputSource(stream);
	}
}
